vector<long long> solve(long long c, vector<vector<long long>> connections, vector<vector<long long>> queries) {
    // Build the DSU (Disjoint Set Union) structure
    vector<long long> parent(c + 1, 0);
    vector<long long> min_id(c + 1, 0);

    // Initialize DSU
    for (long long i = 1; i <= c; ++i) {
        parent[i] = i;
        min_id[i] = i;
    }

    // Union function
    auto unionDSU = [&](long long x, long long y) {
        long long x_root = find(parent, x);
        long long y_root = find(parent, y);
        if (x_root != y_root) {
            parent[y_root] = x_root;
            min_id[x_root] = min(min_id[x_root], min_id[y_root]);
        }
    };

    // Process connections to build the DSU
    for (const auto& conn : connections) {
        long long u = conn[0];
        long long v = conn[1];
        unionDSU(u, v);
    }

    // Track online nodes
    unordered_set<long long> online;
    for (long long i = 1; i <= c; ++i) {
        online.insert(i);
    }

    // Process queries
    vector<long long> result;
    for (const auto& query : queries) {
        if (query[0] == 1) {
            long long x = query[1];
            if (online.find(x) != online.end()) {
                result.push_back(x);
            } else {
                long long root = find(parent, x);
                long long min_id_in_set = min_id[root];
                if (online.find(min_id_in_set) != online.end()) {
                    result.push_back(min_id_in_set);
                } else {
                    result.push_back(-1);
                }
            }
        } else {
            long long x = query[1];
            online.erase(x);
        }
    }

    return result;
}

long long find(vector<long long>& parent, long long x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}
